using System.ComponentModel;
using System.Text;
using System.Text.Json;
using ModelContextProtocol.Server;

namespace ApiMcpServer.Tools;

/// <summary>
/// MCP tools that wrap a REST API via HttpClient.
/// Non-static class — HttpClient and ILogger are constructor-injected by the DI container.
/// </summary>
[McpServerToolType]
public class ApiTools(HttpClient httpClient, ILogger<ApiTools> logger)
{
    [McpServerTool, Description("List all items from the API.")]
    public async Task<string> ListItems(CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Listing items");
        var response = await httpClient.GetAsync("/items", cancellationToken);
        response.EnsureSuccessStatusCode();
        return await response.Content.ReadAsStringAsync(cancellationToken);
    }

    [McpServerTool, Description("Get a single item by its unique identifier.")]
    public async Task<string> GetItem(
        [Description("The unique identifier of the item to retrieve")] string id,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Getting item {Id}", id);
        var response = await httpClient.GetAsync($"/items/{Uri.EscapeDataString(id)}", cancellationToken);
        response.EnsureSuccessStatusCode();
        return await response.Content.ReadAsStringAsync(cancellationToken);
    }

    [McpServerTool, Description("Create a new item with a name and optional description.")]
    public async Task<string> CreateItem(
        [Description("Name for the new item")] string name,
        [Description("Optional description of the item")] string? description = null,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Creating item {Name}", name);
        var payload = JsonSerializer.Serialize(new { name, description });
        var content = new StringContent(payload, Encoding.UTF8, "application/json");
        var response = await httpClient.PostAsync("/items", content, cancellationToken);
        response.EnsureSuccessStatusCode();
        return await response.Content.ReadAsStringAsync(cancellationToken);
    }

    [McpServerTool(ReadOnly = true), Description("Search items by a query string.")]
    public async Task<string> SearchItems(
        [Description("Search query text")] string query,
        [Description("Maximum number of results to return")] int maxResults = 10,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Searching items: {Query}", query);
        var url = $"/items/search?q={Uri.EscapeDataString(query)}&limit={maxResults}";
        var response = await httpClient.GetAsync(url, cancellationToken);
        response.EnsureSuccessStatusCode();
        return await response.Content.ReadAsStringAsync(cancellationToken);
    }
}

